import sqlite3
import time
import requests
import math
from datetime import datetime
from binance.um_futures import UMFutures
from config import DB_PATH, DEFAULT_LEVERAGE

# ============== TESTNET CONFIG ==============
TESTNET_API_KEY = "kc7KNlzjnxqpi8FC28Ms8lM5GTFpvvA30GjdETgTwVVxQbrdEC2GWjOjGxWAdFij"
TESTNET_SECRET = "1UWiGSfGi9wO5sk5FxkjlJJEia18xzafUNQPZ03bZlRP4OxuFO2WRkbR3cRrtsYF"
TESTNET_BASE_URL = "https://testnet.binancefuture.com"
# ============================================


class TestnetEngine:
    def __init__(self):
        self.client = UMFutures(
            key=TESTNET_API_KEY,
            secret=TESTNET_SECRET,
            base_url=TESTNET_BASE_URL
        )
        self.db = sqlite3.connect(DB_PATH)
        self.db.row_factory = sqlite3.Row
        self._init_tables()

    def _init_tables(self):
        cursor = self.db.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS testnet_trades (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                order_id TEXT,
                symbol TEXT NOT NULL,
                side TEXT NOT NULL,
                entry_price REAL,
                quantity REAL,
                leverage INTEGER,
                stop_loss REAL,
                take_profit REAL,
                exit_price REAL,
                pnl REAL DEFAULT 0,
                commission REAL DEFAULT 0,
                status TEXT DEFAULT 'OPEN',
                entry_time TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                exit_time TIMESTAMP,
                notes TEXT
            )
        ''')
        self.db.commit()

    def test_connection(self):
        try:
            acct = self.client.account()
            usdt_balance = 0
            for asset in acct.get('assets', []):
                if asset['asset'] == 'USDT':
                    usdt_balance = float(asset['walletBalance'])
                    break
            positions = [p for p in acct.get('positions', []) if float(p.get('positionAmt', 0)) != 0]
            return {
                'connected': True,
                'usdt_balance': usdt_balance,
                'total_positions': len(positions),
                'positions': positions
            }
        except Exception as e:
            return {'connected': False, 'error': str(e)}

    def get_price(self, symbol='XAUUSDT'):
        try:
            price_data = self.client.ticker_price(symbol)
            return float(price_data['price'])
        except Exception as e:
            print(f"Price error: {e}")
            return None

    def set_leverage(self, symbol='XAUUSDT', leverage=10):
        try:
            self.client.change_leverage(symbol=symbol, leverage=leverage)
            return True
        except:
            return True

    def set_margin_type(self, symbol='XAUUSDT', margin_type='ISOLATED'):
        try:
            self.client.change_margin_type(symbol=symbol, marginType=margin_type)
            return True
        except:
            return True

    def calculate_quantity(self, symbol, price, risk_pct=2.0, leverage=10):
        acct = self.client.account()
        usdt_balance = 0
        for asset in acct.get('assets', []):
            if asset['asset'] == 'USDT':
                usdt_balance = float(asset['walletBalance'])
                break
        if usdt_balance <= 0:
            return 0, usdt_balance
        risk_amount = usdt_balance * risk_pct / 100
        margin_per_unit = price / leverage
        quantity = risk_amount / margin_per_unit
        try:
            info = self.client.exchange_info()
            for s in info['symbols']:
                if s['symbol'] == symbol:
                    for f in s['filters']:
                        if f['filterType'] == 'LOT_SIZE':
                            step_size = float(f['stepSize'])
                            precision = int(round(-math.log(step_size, 10), 0))
                            quantity = round(quantity, precision)
                            min_qty = float(f['minQty'])
                            if quantity < min_qty:
                                quantity = min_qty
                            return quantity, usdt_balance
        except:
            pass
        return round(quantity, 3), usdt_balance

    def open_long(self, symbol='XAUUSDT', risk_pct=2.0, leverage=10, sl_pct=0.5, tp_pct=0.5):
        return self._open_position(symbol, 'BUY', risk_pct, leverage, sl_pct, tp_pct)

    def open_short(self, symbol='XAUUSDT', risk_pct=2.0, leverage=10, sl_pct=0.5, tp_pct=0.5):
        return self._open_position(symbol, 'SELL', risk_pct, leverage, sl_pct, tp_pct)

    def _open_position(self, symbol, side, risk_pct, leverage, sl_pct, tp_pct):
        try:
            price = self.get_price(symbol)
            if not price:
                return {'error': 'Gagal get price'}
            self.set_leverage(symbol, leverage)
            self.set_margin_type(symbol, 'ISOLATED')
            quantity, balance = self.calculate_quantity(symbol, price, risk_pct, leverage)
            if quantity <= 0:
                return {'error': f'Insufficient balance: ${balance:.2f}'}
            if side == 'BUY':
                sl_price = round(price * (1 - sl_pct / 100), 2)
                tp_price = round(price * (1 + tp_pct / 100), 2)
                direction = 'LONG'
            else:
                sl_price = round(price * (1 + sl_pct / 100), 2)
                tp_price = round(price * (1 - tp_pct / 100), 2)
                direction = 'SHORT'

            order = self.client.new_order(
                symbol=symbol, side=side, type='MARKET', quantity=quantity
            )
            order_id = str(order.get('orderId', ''))
            fill_price = float(order.get('avgPrice', price))
            filled_qty = float(order.get('executedQty', quantity))
            commission = float(order.get('commission', 0))

            print(f"MARKET {direction} ORDER FILLED! Price: ${fill_price:,.2f} Qty: {filled_qty}")

            # SL
            try:
                self.client.new_order(
                    symbol=symbol,
                    side='SELL' if side == 'BUY' else 'BUY',
                    type='STOP_MARKET',
                    stopPrice=sl_price,
                    quantity=filled_qty
                )
                print(f"  SL placed at ${sl_price:,.2f}")
            except Exception as e:
                print(f"  SL error: {e}")

            # TP
            try:
                self.client.new_order(
                    symbol=symbol,
                    side='SELL' if side == 'BUY' else 'BUY',
                    type='TAKE_PROFIT_MARKET',
                    stopPrice=tp_price,
                    quantity=filled_qty
                )
                print(f"  TP placed at ${tp_price:,.2f}")
            except Exception as e:
                print(f"  TP error: {e}")

            # Save to DB
            cursor = self.db.cursor()
            cursor.execute('''
                INSERT INTO testnet_trades 
                (order_id, symbol, side, entry_price, quantity, leverage, stop_loss, take_profit, commission, status)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'OPEN')
            ''', (order_id, symbol, direction, fill_price, filled_qty, leverage, sl_price, tp_price, commission))
            self.db.commit()
            trade_id = cursor.lastrowid

            return {
                'success': True, 'trade_id': trade_id, 'order_id': order_id,
                'symbol': symbol, 'direction': direction, 'entry_price': fill_price,
                'quantity': filled_qty, 'leverage': leverage, 'stop_loss': sl_price,
                'take_profit': tp_price, 'margin_used': round((fill_price * filled_qty) / leverage, 2),
                'commission': commission
            }
        except Exception as e:
            return {'error': str(e)}

    def close_position(self, symbol='XAUUSDT'):
        try:
            positions = self.client.position_risk(symbol=symbol)
            for pos in positions:
                amt = float(pos['positionAmt'])
                if amt == 0:
                    continue
                close_side = 'SELL' if amt > 0 else 'BUY'
                close_qty = abs(amt)
                order = self.client.new_order(
                    symbol=symbol, side=close_side, type='MARKET', quantity=close_qty
                )
                exit_price = float(order.get('avgPrice', 0))
                pnl = float(pos.get('unRealizedProfit', 0))
                print(f"Position CLOSED! PnL: ${pnl:+.2f}")
                return {
                    'success': True, 'direction': 'LONG' if amt > 0 else 'SHORT',
                    'entry_price': float(pos['entryPrice']), 'exit_price': exit_price,
                    'pnl': round(pnl, 2), 'quantity': close_qty
                }
            return {'error': 'No open position found'}
        except Exception as e:
            return {'error': str(e)}

    def get_account(self):
        try:
            acct = self.client.account()
            balances = {}
            for asset in acct.get('assets', []):
                bal = float(asset['walletBalance'])
                if bal != 0:
                    balances[asset['asset']] = {
                        'balance': bal,
                        'unrealized_pnl': float(asset.get('unrealizedProfit', 0)),
                        'margin_balance': float(asset.get('marginBalance', 0))
                    }
            positions = []
            for p in acct.get('positions', []):
                if float(p.get('positionAmt', 0)) != 0:
                    positions.append({
                        'symbol': p['symbol'], 'side': p['positionSide'],
                        'amount': float(p['positionAmt']), 'entry_price': float(p['entryPrice']),
                        'mark_price': float(p.get('markPrice', 0)),
                        'unrealized_pnl': float(p.get('unRealizedProfit', 0)),
                        'leverage': int(p.get('leverage', 1)),
                        'liquidation_price': float(p.get('liquidationPrice', 0))
                    })
            orders = self.client.get_open_orders()
            return {
                'balances': balances, 'positions': positions,
                'open_orders': len(orders), 'orders': orders
            }
        except Exception as e:
            return {'error': str(e)}

    def get_open_orders(self, symbol=None):
        try:
            if symbol:
                return self.client.get_open_orders(symbol=symbol)
            return self.client.get_open_orders()
        except Exception as e:
            return {'error': str(e)}

    def cancel_all_orders(self, symbol='XAUUSDT'):
        try:
            result = self.client.cancel_open_orders(symbol=symbol)
            print(f"All orders cancelled for {symbol}")
            return result
        except Exception as e:
            return {'error': str(e)}

